using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.name, Price = e.price, Quantity = e.qty }).ToList();

    // --- CreateOrder: success paths ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 5.50m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(36.50m, order.Total); // 10*2 + 5.50*3
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithOneItem()
    {
        var items = CreateItems(("Solo", 25.00m, 1));

        var order = _sut.CreateOrder("cust-2", items);

        Assert.AreEqual(25.00m, order.Total);
        var single = Assert.ContainsSingle(order.Items);
        Assert.AreEqual("Solo", single.ProductName);
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueId()
    {
        var items = CreateItems(("Item", 1m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order1.Id);
        Assert.IsNotNull(order2.Id);
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Item", 1m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    // --- CreateOrder: error paths ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Item", 1m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    // --- CreateOrder: total calculation with DataRow ---

    [TestMethod]
    [DataRow(10.00, 1, 10.00, DisplayName = "Single unit")]
    [DataRow(7.50, 4, 30.00, DisplayName = "Multiple units")]
    [DataRow(0.01, 100, 1.00, DisplayName = "Penny items")]
    public void CreateOrder_CalculatesTotalCorrectly(double price, int qty, double expectedTotal)
    {
        var items = CreateItems(("Product", (decimal)price, qty));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var items = CreateItems(("Item", 5m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var retrieved = _sut.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllForCustomer()
    {
        var items = CreateItems(("Item", 1m, 1));
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items);

        var results = _sut.GetOrdersByCustomer("cust-A");

        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var results = _sut.GetOrdersByCustomer("nobody");

        Assert.IsNotEmpty(results is not null ? [] : []);
        Assert.IsEmpty(results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomerOrders()
    {
        var items = CreateItems(("Item", 1m, 1));
        var otherOrder = _sut.CreateOrder("cust-other", items);

        var results = _sut.GetOrdersByCustomer("cust-mine");

        Assert.IsEmpty(results);
        Assert.DoesNotContain(otherOrder, results);
    }
}

