14.     }
15. 
16.     private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] entries) =>
17.         entries.Select(e => new OrderItem { ProductName = e.name, Price = e.price, Quantity = e.qty }).ToList();
18. 
19.     // --- CreateOrder: success paths ---
