21.     [TestMethod]
22.     public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
23.     {
24.         // Arrange
25.         var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 5.50m, 3));
26. 
27.         // Act
28.         var order = _sut.CreateOrder("cust-1", items);
29. 
30.         // Assert
31.         Assert.IsNotNull(order);
32.         Assert.AreEqual("cust-1", order.CustomerId);
33.         Assert.AreEqual(36.50m, order.Total); // 10*2 + 5.50*3
34.         Assert.HasCount(2, order.Items);
35.     }
36. 
37.     [TestMethod]
38.     public void CreateOrder_WithSingleItem_ReturnsOrderWithOneItem()
39.     {
40.         var items = CreateItems(("Solo", 25.00m, 1));
41. 
42.         var order = _sut.CreateOrder("cust-2", items);
43. 
44.         Assert.AreEqual(25.00m, order.Total);
45.         var single = Assert.ContainsSingle(order.Items);
46.         Assert.AreEqual("Solo", single.ProductName);
47.     }
48. 
